# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    # Connect to the RDS MySQL instance
    db = pymysql.connect(host='localhost', user='root', passwd='password', db='database')
    
    # Extract the search parameters from the event
    search_params = json.loads(event['body'])
    
    # Build a dynamic SQL query based on the search parameters
    query = "SELECT * FROM products"
    if 'product_name' in search_params:
        query += f" WHERE name LIKE '%{search_params['product_name']}%'"
    if 'product_category' in search_params:
        query += f" AND category = '{search_params['product_category']}'"
    
    # Execute the SQL query and fetch the results
    with db.cursor() as cursor:
        cursor.execute(query)
        products = cursor.fetchall()
    
    # Close the database connection
    db.close()
    
    # Return the search results in JSON format
    return {
        'statusCode': 200,
        'body': json.dumps({'products': products})
    }